function toks(s){ const raw=trmap(String(s||'').toLowerCase()).replace(/[^a-z0-9\s-]/g,' ').split(/[\s-]+/); const seen=new Set(); const outT=[]; for(const w0 of raw){ const w=ALIAS[w0]||w0; if(w.length>=3 && !STOP.has(w) && !/^\d+$/.test(w) && !seen.has(w)){ seen.add(w); outT.push(w); } } return outT; }
const feeds=[['BBC','Kaynak BBC'],['Guardian','Kaynak Guardian'],['AlJazeera','Kaynak Al Jazeera'],['AA','Kaynak AA']];
const arts=[]; const feedDurum={};
for(const f of feeds){ const xml=grab(f[1]); const its=xml?parseRss(xml).slice(0,60):[]; feedDurum[f[0]]=its.length; for(const it of its){ if(!it.title) continue; const t=toks(it.title+' '+String(it.desc||'').slice(0,160)); if(t.length<2) continue; arts.push({src:f[0], title:it.title, link:it.link, tokens:t}); } }
const clusters=[];
function topOf(c,n){ return Object.entries(c.tokenCount).sort(function(x,y){return y[1]-x[1];}).slice(0,n).map(function(e){return e[0];}); }
