      const g=await this.helpers.httpRequest({method:'GET',url:'https://api.gdeltproject.org/api/v2/doc/doc',qs:{query:q,mode:'artlist',maxrecords:100,timespan:'1d',format:'json',sort:'hybridrel'},headers:{'User-Agent':UA},json:false});
      const s=String(g||'');
      if(s.indexOf('limit requests')>=0) throw new Error('gdelt-throttle');
      const ds=new Set(); const dre=/"domain":\s*"([^"]+)"/g; let dm;
