function ayikla(t){ const s=String(t||'').replace(/```json/gi,'').replace(/```/g,''); const a=s.indexOf('{'); const b=s.lastIndexOf('}'); if(a<0||b<=a) throw new Error('JSON bulunamadi'); return JSON.parse(s.slice(a,b+1)); }
