    +'\n🏷 Anahtar kelimeler: '+esc(f.anahtar_kelimeler||'')
    +'\n🔗 '+esc(f.link||'');
  const body={chat_id:chat,text:text,parse_mode:'HTML',link_preview_options:{is_disabled:true},reply_markup:{inline_keyboard:[[{text:'✅ Onayla',callback_data:'ok:'+rowId},{text:'❌ Reddet',callback_data:'no:'+rowId}]]}};
  const r=await this.helpers.httpRequest({method:'POST',url:api+'/sendMessage',body:body,json:true});
  sonuc.push({json:{gonderildi:true,message_id:(r&&r.result&&r.result.message_id)||null,rowId:rowId,baslik:f.baslik,skor:f.skor}});
}
return sonuc;
